impl Solution { pub fn max_frequency(nums: Vec<i32>, k: i32) -> i32 { let mut black_base = nums.iter().filter(|&&x| x == k).count() as i32; let mut black_max_gain = 0; for target in 1..=50 { if target == k { continue; } let (mut curr, mut best) = (0, 0); for &x in &nums { if x == target { curr += 1; } else if x == k { curr -= 1; } if curr < 0 { curr = 0; } if curr > best { best = curr; } } black_max_gain = black_max_gain.max(best); } black_base + black_max_gain } }